249→            if (mCardList != null && mCardListIndex >= 0 && mCardListIndex < mCardList!!.size) {
250→                currentCard = PreviewerCard(col, mCardList!![mCardListIndex])
251→            } else if (mEditedNotetype != null) { // bare note type (not coming from note editor), or new card template
252→                Timber.d("onCreate() CardTemplatePreviewer started with edited model and template index, displaying blank to preview formatting")
253→                currentCard = getDummyCard(mEditedNotetype!!, mOrdinal)
254→                if (currentCard == null) {
255→                    showThemedToast(applicationContext, getString(R.string.invalid_template), false)
256→                    closeCardTemplatePreviewer()
