427→private class EphemeralCard(col: Collection, id: Long?) : Card(col, id) {
428→    override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
429→        return this.renderOutput!!
430→    }
431→    companion object {
432→        fun fromNote(n: Note, col: Collection, cardIndex: Int = 0): EphemeralCard {
433→            val card = EphemeralCard(col, null)
434→            card.did = 1
435→            card.ord = n.cardIndexToOrd(cardIndex)
436→
437→            val nt = n.notetype
438→            val templateIdx = if (nt.type == Consts.MODEL_CLOZE) {
439→                0
440→            } else {
441→                cardIndex
442→            }
443→            val template = nt.tmpls[templateIdx] as JSONObject
444→            template.put("ord", card.ord)
445→
446→            val output = TemplateManager.TemplateRenderContext.fromCardLayout(
447→                n,
448→                card,
449→                notetype = nt,
450→                template = template,
451→                fillEmpty = false
452→            ).render()
453→            card.renderOutput = output
454→            card.setNote(n)
455→            return card
456→        }
457→    }
458→}
