     * Converts a card ordinal to its index in the list of cards
     * For non-cloze notes, ordinal == cardIndex
     * For cloze notes, we need to find the index of the cloze number in the note
     * @param col The collection
     * @param ordinal The card's ordinal value
     * @return The index of the card in the list of cards
     */
    private fun ordinalToCardIndex(col: Collection, ordinal: Int): Int {
        if (mEditedNotetype?.isCloze != true || mNoteEditorBundle == null) {
            return ordinal
        }

        // For cloze notes, we need to create a temporary note to get the cloze numbers
        val fieldValues = getBundleEditFields(mNoteEditorBundle)
        val tempNote = col.newNote(mEditedNotetype!!)
        var i = 0
        while (i < fieldValues.size && i < tempNote.fields.size) {
            tempNote.setField(i, fieldValues[i])
            i++
        }

        val clozeNumbers = col.clozeNumbersInNote(tempNote)
        // ordinal is 0-based, but cloze numbers are 1-based
        val targetClozeNumber = ordinal + 1
        val index = clozeNumbers.indexOf(targetClozeNumber)

        // If not found, fall back to 0
        return if (index >= 0) index else 0
    }

    private fun setCurrentCardFromNoteEditorBundle(col: Collection): Card? {
        assert(mNoteEditorBundle != null)
        currentCard = getDummyCard(mEditedNotetype, cardIndex, getBundleEditFields(mNoteEditorBundle))
        // example: a basic card with no fields provided
        if (currentCard == null) {
            return null
        }
