        if (col.decks.isDyn(newDid)) {
            currentCard!!.oDid = currentCard!!.did
        }
        currentCard!!.did = newDid
        val currentNote = currentCard!!.note()
        val tagsList = mNoteEditorBundle!!.getStringArrayList("tags")
        setTags(currentNote, tagsList)
        return currentCard
    }"}

