package com.ichi2.anki

import android.content.Intent
import androidx.core.os.bundleOf
import com.ichi2.anki.servicelayer.NoteService
import org.hamcrest.CoreMatchers.*
import org.hamcrest.MatcherAssert.assertThat
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.RobolectricTestRunner

/**
 * Tests for Issue 14694: Edit Note Preview does not show the expected card
 * Tests that the ordinal parameter is correctly used to display the selected card
 */
@RunWith(RobolectricTestRunner::class)
class CardTemplatePreviewerOrdinalTest : RobolectricTest() {

    @Test
    fun `ordinal is used for standard note type - Issue 14694`() {
        val fields: MutableList<NoteService.NoteField?> = arrayListOf(
            Field(0, "Hello"),
            Field(1, "World")
        )

        val intent = Intent(Intent.ACTION_VIEW).apply {
            val basicModel = getCurrentDatabaseModelCopy("Basic (and reversed card)")
            val tempModelPath = CardTemplateNotetype.saveTempModel(targetContext, basicModel)
            putExtra(CardTemplateNotetype.INTENT_MODEL_FILENAME, tempModelPath)
            putExtra(
                "noteEditorBundle",
                bundleOf(
                    "editFields" to NoteService.getFieldsAsBundleForPreview(fields),
                    "did" to 1L
                )
            )
            putExtra("ordinal", 1) // Second card (reversed)
        }

        val testCardTemplatePreviewer = super.startActivityNormallyOpenCollectionWithIntent(
            TestCardTemplatePreviewer::class.java,
            intent
        )

        assertThat("cardIndex should be 1", testCardTemplatePreviewer.cardIndex, equalTo(1))
        assertThat("Front is not displayed", testCardTemplatePreviewer.cardContent, not(containsString("Hello")))
        assertThat("Back is displayed", testCardTemplatePreviewer.cardContent, containsString("World"))
    }

    @Test
    fun `ordinal is used for cloze note type - Issue 14694`() {
        val fields: MutableList<NoteService.NoteField?> = arrayListOf(
            Field(0, "{{c1::Hello}} {{c3::World}}"),
            Field(1, "Extra")
        )
        val ordinalOfSecondCard = 2 // c3

        val intent = Intent(Intent.ACTION_VIEW).apply {
            val clozeModel = getCurrentDatabaseModelCopy("Cloze")
            val tempModelPath = CardTemplateNotetype.saveTempModel(targetContext, clozeModel)
            putExtra(CardTemplateNotetype.INTENT_MODEL_FILENAME, tempModelPath)
            putExtra(
                "noteEditorBundle",
                bundleOf(
                    "editFields" to NoteService.getFieldsAsBundleForPreview(fields),
                    "did" to 1L
                )
            )
            putExtra("ordinal", ordinalOfSecondCard)
        }

        val testCardTemplatePreviewer = super.startActivityNormallyOpenCollectionWithIntent(
            TestCardTemplatePreviewer::class.java,
            intent
        )

        assertThat("cardIndex should be 1", testCardTemplatePreviewer.cardIndex, equalTo(1))
        assertThat("Hello is displayed", testCardTemplatePreviewer.cardContent, containsString("Hello"))
        assertThat("World is hidden (cloze)", testCardTemplatePreviewer.cardContent, not(containsString("World")))
    }

    @Test
    fun `ordinal 0 shows first card for standard note type`() {
        val fields: MutableList<NoteService.NoteField?> = arrayListOf(
            Field(0, "Front"),
            Field(1, "Back")
        )

        val intent = Intent(Intent.ACTION_VIEW).apply {
            val basicModel = getCurrentDatabaseModelCopy("Basic (and reversed card)")
            val tempModelPath = CardTemplateNotetype.saveTempModel(targetContext, basicModel)
            putExtra(CardTemplateNotetype.INTENT_MODEL_FILENAME, tempModelPath)
            putExtra(
                "noteEditorBundle",
                bundleOf(
                    "editFields" to NoteService.getFieldsAsBundleForPreview(fields),
                    "did" to 1L
                )
            )
            putExtra("ordinal", 0) // First card
        }

        val testCardTemplatePreviewer = super.startActivityNormallyOpenCollectionWithIntent(
            TestCardTemplatePreviewer::class.java,
            intent
        )

        assertThat("cardIndex should be 0", testCardTemplatePreviewer.cardIndex, equalTo(0))
        assertThat("Front is displayed", testCardTemplatePreviewer.cardContent, containsString("Front"))
    }

    @Test
    fun `ordinal 0 shows first cloze card`() {
        val fields: MutableList<NoteService.NoteField?> = arrayListOf(
            Field(0, "{{c1::Alpha}} {{c2::Beta}}"),
            Field(1, "Extra")
        )

        val intent = Intent(Intent.ACTION_VIEW).apply {
            val clozeModel = getCurrentDatabaseModelCopy("Cloze")
            val tempModelPath = CardTemplateNotetype.saveTempModel(targetContext, clozeModel)
            putExtra(CardTemplateNotetype.INTENT_MODEL_FILENAME, tempModelPath)
            putExtra(
                "noteEditorBundle",
                bundleOf(
                    "editFields" to NoteService.getFieldsAsBundleForPreview(fields),
                    "did" to 1L
                )
            )
            putExtra("ordinal", 0) // c1
        }

        val testCardTemplatePreviewer = super.startActivityNormallyOpenCollectionWithIntent(
            TestCardTemplatePreviewer::class.java,
            intent
        )

        assertThat("cardIndex should be 0", testCardTemplatePreviewer.cardIndex, equalTo(0))
        assertThat("Beta is displayed", testCardTemplatePreviewer.cardContent, containsString("Beta"))
        assertThat("Alpha is hidden (cloze)", testCardTemplatePreviewer.cardContent, not(containsString("Alpha")))
    }

    @Test
    fun `navigation buttons are properly enabled for middle card`() {
        val fields: MutableList<NoteService.NoteField?> = arrayListOf(
            Field(0, "{{c1::One}} {{c2::Two}} {{c3::Three}}"),
            Field(1, "Extra")
        )

        val intent = Intent(Intent.ACTION_VIEW).apply {
            val clozeModel = getCurrentDatabaseModelCopy("Cloze")
            val tempModelPath = CardTemplateNotetype.saveTempModel(targetContext, clozeModel)
            putExtra(CardTemplateNotetype.INTENT_MODEL_FILENAME, tempModelPath)
            putExtra(
                "noteEditorBundle",
                bundleOf(
                    "editFields" to NoteService.getFieldsAsBundleForPreview(fields),
                    "did" to 1L
                )
            )
            putExtra("ordinal", 1) // c2 (middle card)
        }

        val testCardTemplatePreviewer = super.startActivityNormallyOpenCollectionWithIntent(
            TestCardTemplatePreviewer::class.java,
            intent
        )

        assertThat("cardIndex should be 1", testCardTemplatePreviewer.cardIndex, equalTo(1))
        assertThat("prev should be enabled", testCardTemplatePreviewer.previousButtonEnabled(), equalTo(true))
        assertThat("next should be enabled", testCardTemplatePreviewer.nextButtonEnabled(), equalTo(true))
    }

    private inner class Field(override val ord: Int, private val text: String) : NoteService.NoteField {
        override val fieldText: String
            get() = text
    }
}
